const body = $input.first().json.body || $input.first().json;

// Detect content type — handles Supabase-normalized format AND raw Z-API format
let contentType       = body.content_type || 'text';
let mediaUrl          = body.media_url    || null;
let transcriptionText = body.transcription_text || null;
let contentText       = body.content_text || body.message_text || '';
let fileName          = body.file_name    || null;
let mediaDuration     = body.media_duration_sec || null;

// Raw Z-API field fallbacks (if webhook reaches n8n before pre-processing)
if (!mediaUrl) {
  if (body.audio?.audioUrl) {
    contentType   = 'audio';
    mediaUrl      = body.audio.audioUrl;
    mediaDuration = body.audio.seconds || null;
    transcriptionText = body.audio.transcription || null;
  } else if (body.video?.videoUrl) {
    contentType = 'video';
    mediaUrl    = body.video.videoUrl;
    contentText = body.video.caption || contentText;
  } else if (body.document?.documentUrl) {
    contentType = 'document';
    mediaUrl    = body.document.documentUrl;
    fileName    = body.document.fileName || body.document.title || null;
    contentText = body.document.caption || contentText;
  } else if (body.image?.imageUrl) {
    contentType = 'image';
    mediaUrl    = body.image.imageUrl;
    contentText = body.image.caption || contentText;
  }
}

return [{ json: {
  tenant_id:          body.tenant_id       || '5518085b-42e9-4608-8c56-890cef45ba9b',
  customer_id:        body.customer_id,
  conversation_id:    body.conversation_id,
  channel_id:         body.channel_id      || '58c4062a-9fe9-4ae2-abff-5a8b5236a79e',
  content_text:       contentText,
  content_type:       contentType,
  media_url:          mediaUrl,
  transcription_text: transcriptionText,
  file_name:          fileName,
  media_duration_sec: mediaDuration,
  customer_name:      body.customer_name   || 'Cliente',
  customer_phone:     body.customer_phone  || body.phone || '',
}}];

const payload    = $('Normalizar Payload').first().json;
const messages   = $('Buscar Histórico').all().map(i => i.json);
const agentCfg   = $('Buscar Config IA').first().json || {};
const aiContext  = $('Buscar Contexto Empresa').first().json?.ai_context_text || '';

// Build conversation history, labelling media messages properly
const history = messages.slice(-15).map(m => {
  const role = m.direction === 'inbound' ? 'Cliente' : 'Sofia';
  let text = m.content_text || '';
  if (!text) {
    if (m.content_type === 'audio')    text = '[Mensagem de voz]';
    else if (m.content_type === 'video')    text = '[Vídeo]';
    else if (m.content_type === 'document') text = '[Documento]';
    else if (m.content_type === 'image')    text = '[Imagem]';
  }
  return `${role}: ${text}`;
}).join('\n');

// Build user message based on what was received
const contentType = payload.content_type || 'text';
let userMessage   = payload.content_text || '';

if (contentType === 'audio') {
  if (payload.transcription_text) {
    userMessage = `[Mensagem de voz transcrita]: ${payload.transcription_text}`;
  } else {
    const dur = payload.media_duration_sec ? ` de ${payload.media_duration_sec}s` : '';
    userMessage = `[O cliente enviou uma mensagem de voz${dur}. A transcrição automática não está disponível. Peça gentilmente para o cliente repetir por texto se necessário.]`;
  }
} else if (contentType === 'video') {
  userMessage = payload.content_text
    ? `[O cliente enviou um vídeo com legenda]: ${payload.content_text}`
    : '[O cliente enviou um vídeo. Responda naturalmente e pergunte como pode ajudá-lo.]';
} else if (contentType === 'document') {
  const fname = payload.file_name ? ` "${payload.file_name}"` : "";
  userMessage = payload.content_text
    ? `[O cliente enviou um documento${fname} com comentário]: ${payload.content_text}`
    : `[O cliente enviou um documento${fname}. Pergunte como pode ajudá-lo em relação a este documento.]`;
} else if (contentType === 'image') {
  userMessage = payload.content_text
    ? `[O cliente enviou uma imagem com legenda]: ${payload.content_text}`
    : '[O cliente enviou uma imagem. Responda naturalmente e pergunte como pode ajudá-lo.]';
}

const now     = new Date();
const dateStr = now.toLocaleDateString('pt-BR', { weekday:'long', year:'numeric', month:'long', day:'numeric', timeZone:'America/Sao_Paulo' });
const timeStr = now.toLocaleTimeString('pt-BR', { hour:'2-digit', minute:'2-digit', timeZone:'America/Sao_Paulo' });

const base = agentCfg.system_prompt || 'Você é Sofia, assistente virtual de uma clínica especializada.';

const systemPrompt = `${base}

=== DADOS DA EMPRESA ===
${aiContext || '(dados não disponíveis no momento)'}

=== REGRAS OBRIGATÓRIAS SOBRE DADOS DA EMPRESA ===
- Use SOMENTE os dados da seção "=== DADOS DA EMPRESA ===" para responder perguntas sobre endereço, telefone, WhatsApp, horários, serviços e profissionais.
- Se uma informação não estiver listada na seção "=== DADOS DA EMPRESA ===", responda: "Não tenho essa informação disponível no momento. Posso verificar com nossa equipe e te retorno."
- NUNCA invente endereços, telefones, serviços, nomes de profissionais ou preços.
- NUNCA mencione serviços ou profissionais que não estejam listados acima.

=== CONTEXTO DA CONVERSA ===
Data/hora atual: ${dateStr} às ${timeStr} (horário de Brasília, UTC-3)
ID da conversa: ${payload.conversation_id}
Cliente: ${payload.customer_name} | Telefone: ${payload.customer_phone}

=== HISTÓRICO RECENTE ===
${history || '(início da conversa)'}

=== REGRAS OPERACIONAIS ===
- Responda SEMPRE em português brasileiro natural e humanizado. NUNCA mencione IA, robô ou sistemas.
- Para verificar disponibilidade de horários, use a ferramenta verificar_horarios.
- Apresente até 3 opções de horário de forma amigável. Aguarde o cliente escolher UMA opção antes de agendar.
- Use confirmar_agendamento SOMENTE após o cliente confirmar explicitamente o horário desejado.
- Ao chamar ferramentas, sempre inclua p_conversation_id = ${payload.conversation_id}
- Datas para agendamento em formato ISO com timezone -03:00. Exemplo: 2026-04-14T09:00:00-03:00
- Após confirmar agendamento, informe: serviço, profissional, data, horário e que um lembrete será enviado.`;

return [{ json: { ...payload, system_prompt: systemPrompt, user_message: userMessage }}];
